const a=[{id:"ball-python",name:"Ball Python",latin:"Python regius",family:"Pythons",familyLatin:"Pythonidae",region:"West & Central Africa",venomous:!1,length:"3–5 ft",lifespan:"20–30 yrs",conservation:"NT",diet:"Rodents — wild prey is mostly African soft-furred rats",short:"The world's most popular pet snake — calm, slow-moving, and bred into hundreds of color morphs.",long:"Ball pythons get their name from their defensive habit of curling into a tight ball, head tucked safely in the middle, rather than striking. In the wild they shelter in abandoned mammal burrows and termite mounds across the grasslands and open forests of West Africa, emerging at night to ambush rodents. Decades of captive breeding have produced an enormous range of colors and patterns, making them the most commonly kept pet snake on Earth.",fact:"A single 'morph' — like the Pastel or Piebald — can sell for anywhere from $50 to several thousand dollars depending on how rare the genetic combination is.",isPet:!0,isEndangered:!1,homeFeatured:!0,palette:{primary:"#5a7a3d",secondary:"#2f4022",belly:"#e8dcae"},pattern:"blotch",petDiet:{staple:"Frozen-thawed mice or rats, sized no wider than the snake's body",freq:"Once every 1–2 weeks for adults; weekly for juveniles",size:"1 appropriately-sized rodent per feeding",tip:"Ball pythons are notorious 'picky eaters' — a short fast during shedding or stress is normal, not an emergency."}},{id:"burmese-python",name:"Burmese Python",latin:"Python bivittatus",family:"Pythons",familyLatin:"Pythonidae",region:"South & Southeast Asia",venomous:!1,length:"10–18 ft",lifespan:"20–25 yrs",conservation:"VU",diet:"Birds and mammals up to deer-sized in the wild",short:"One of the five largest snakes alive, and now a notorious invasive apex predator in the Florida Everglades.",long:"In its native range across Southeast Asian wetlands and grasslands, the Burmese python is a powerful ambush predator capable of swallowing prey many times its own body weight. Released or escaped pets established a breeding population in the Florida Everglades in the 1980s–90s, where they have devastated native mammal populations with no natural predators to check them.",fact:"Researchers have documented Everglades Burmese pythons eating full-grown white-tailed deer and even American alligators.",isPet:!1,isEndangered:!1,homeFeatured:!0,palette:{primary:"#7a6b46",secondary:"#3a3220",belly:"#e6dcc0"},pattern:"blotch"},{id:"reticulated-python",name:"Reticulated Python",latin:"Malayopython reticulatus",family:"Pythons",familyLatin:"Pythonidae",region:"Southeast Asia",venomous:!1,length:"10–20 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Mammals and birds, taken by ambush near water",short:"The longest snake species on the planet, with a shimmering geometric pattern that gives it its name.",long:"Named for the net-like (reticulated) pattern across its scales, this python holds the record for greatest confirmed length of any living snake, with some individuals verified beyond 20 feet. It is a strong swimmer often found near rivers and mangroves, and despite its size is a capable climber as a juvenile.",fact:"Reticulated python scales have an iridescent sheen that shifts color in different light, a side effect of microscopic scale ridges rather than pigment.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#8a7a4a",secondary:"#2c2416",belly:"#e8dcae"},pattern:"diamond"},{id:"green-tree-python",name:"Green Tree Python",latin:"Morelia viridis",family:"Pythons",familyLatin:"Pythonidae",region:"New Guinea & Cape York, Australia",venomous:!1,length:"4–6 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Small mammals and reptiles, ambushed from a branch",short:"A vivid emerald canopy-dweller that spends its life coiled over a branch in a signature saddle pose.",long:"Hatchlings are born bright yellow or brick red and only turn green after several months, an unusual color change among snakes. Adults rest draped over branches with their coils folded into a neat saddle shape, striking downward at anything that passes below. It occupies the same rainforest niche in New Guinea that the unrelated emerald tree boa fills in South America — a classic case of convergent evolution.",fact:"Its lookalike, the emerald tree boa of the Amazon, evolved the identical saddle-perch posture independently on the other side of the world.",isPet:!1,isEndangered:!1,homeFeatured:!0,palette:{primary:"#3f8f4f",secondary:"#245c2e",belly:"#cfe6b0"},pattern:"speckle"},{id:"carpet-python",name:"Carpet Python",latin:"Morelia spilota",family:"Pythons",familyLatin:"Pythonidae",region:"Australia & New Guinea",venomous:!1,length:"6–9 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Birds, mammals, and other reptiles",short:"A highly variable python whose intricate patterning is said to resemble a woven carpet.",long:"Carpet pythons range across nearly every habitat in Australia, from coastal forests to arid scrub, and subspecies vary enormously in color from jet-black jungle carpets to golden-striped coastal forms. They are strong climbers and frequently take shelter in roof cavities, making them a common, generally welcome, backyard visitor that keeps rodent numbers down.",fact:"Many Australian homeowners deliberately leave roof access open for carpet pythons because they're such effective rat control.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#4a3d2a",secondary:"#1c1710",belly:"#c9b98a"},pattern:"diamond"},{id:"blood-python",name:"Blood Python",latin:"Python brongersmai",family:"Pythons",familyLatin:"Pythonidae",region:"Malay Peninsula, Sumatra",venomous:!1,length:"4–6 ft",lifespan:"18–25 yrs",conservation:"LC",diet:"Small mammals in swampy lowland forest",short:"A short, heavy-bodied swamp python known for deep rust-red coloring and a famously grumpy temperament.",long:"Blood pythons are built almost like living fire hydrants — extremely thick-bodied relative to their length. They favor lowland swamps and rice paddies, ambushing prey from a coiled, motionless position. Their striking rust-and-black coloration made them popular in the leather trade long before the pet industry took interest.",fact:"Despite a reputation for being defensive, selectively bred captive blood pythons today are often calmer than their wild-caught ancestors.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#8a3324",secondary:"#3a140f",belly:"#d9b88f"},pattern:"blotch"},{id:"african-rock-python",name:"African Rock Python",latin:"Python sebae",family:"Pythons",familyLatin:"Pythonidae",region:"Sub-Saharan Africa",venomous:!1,length:"10–16 ft",lifespan:"12–20 yrs",conservation:"LC",diet:"Antelope, monkeys, and large rodents",short:"Africa's largest snake, and one of only a handful of pythons known to have preyed on humans in rare cases.",long:"Africa's biggest constrictor is a powerful generalist predator found near water across the sub-Saharan savanna. Unlike the more docile ball python, it has a reputation for aggression when cornered. Females are attentive mothers, coiling around their eggs for the entire incubation period and even shivering to generate warmth.",fact:"Female rock pythons can raise their body temperature several degrees above the surrounding air by rhythmically contracting their muscles around the egg clutch.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#6b6b3d",secondary:"#2c2c18",belly:"#d8cf9a"},pattern:"blotch"},{id:"woma-python",name:"Woma Python",latin:"Aspidites ramsayi",family:"Pythons",familyLatin:"Pythonidae",region:"Australian desert interior",venomous:!1,length:"4–6 ft",lifespan:"20–25 yrs",conservation:"NT",diet:"Reptiles and small mammals, hunted underground",short:"A desert-specialist python that hunts inside burrows and uses its tail as a decoy while its head strikes.",long:"The Woma has lost the heat-sensing pits found in most pythons, likely because its favored hunting ground — sand burrows shared with prey — makes them less useful. It is famous for a defensive and hunting trick: while its head does the biting, its tail wriggles nearby to distract or confuse prey and predators alike.",fact:"Womas will pin struggling prey against the wall of a burrow using body coils instead of fully constricting, since there's no room to coil in a tight tunnel.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#9a7a4a",secondary:"#5c4526",belly:"#e6d8a8"},pattern:"band"},{id:"boa-constrictor",name:"Boa Constrictor",latin:"Boa constrictor",family:"Boas",familyLatin:"Boidae",region:"Central & South America",venomous:!1,length:"6–10 ft",lifespan:"20–30 yrs",conservation:"LC",diet:"Birds and mammals ambushed near trails or water",short:"The species that gave 'constriction' its name — a patient ambush predator found across two continents.",long:"Boa constrictors are generalists, thriving in habitats from rainforest to semi-desert scrub across a huge range. They give birth to live young rather than laying eggs, sometimes 60 or more in a single litter. Contrary to old belief, research shows constriction doesn't work by suffocation alone — it also cuts off blood flow to the brain within seconds.",fact:"A 2015 study found boas match their squeeze pressure to their prey's heartbeat in real time, tightening further each time they detect a pulse.",isPet:!0,isEndangered:!1,homeFeatured:!0,palette:{primary:"#7a5a3d",secondary:"#3a2818",belly:"#e0c99a"},pattern:"saddle",petDiet:{staple:"Frozen-thawed rats, moving up to rabbits as adults",freq:"Every 1–2 weeks for adults, weekly for young snakes",size:"Prey roughly the width of the snake's thickest point",tip:"Boas grow large and strong — always use two hands and have a spotter for anything over 6 feet."}},{id:"green-anaconda",name:"Green Anaconda",latin:"Eunectes murinus",family:"Boas",familyLatin:"Boidae",region:"Amazon & Orinoco basins",venomous:!1,length:"15–29 ft",lifespan:"10–12 yrs",conservation:"LC",diet:"Capybara, deer, caiman, and large fish",short:"The heaviest snake on Earth — a semi-aquatic ambush hunter that can weigh more than 250 lbs.",long:"Anacondas spend most of their lives submerged in slow rivers and swamps, with eyes and nostrils positioned on top of the head so they can watch for prey while staying almost entirely hidden. Unlike most snakes, females are dramatically larger than males, sometimes several times their weight — an unusual degree of sexual size difference among vertebrates.",fact:"An anaconda's buoyancy in water lets it ambush prey many times its own weight, something it likely couldn't manage on land.",isPet:!1,isEndangered:!1,homeFeatured:!0,palette:{primary:"#38502f",secondary:"#182a16",belly:"#c8c088"},pattern:"blotch"},{id:"rosy-boa",name:"Rosy Boa",latin:"Lichanura trivirgata",family:"Boas",familyLatin:"Boidae",region:"American Southwest & Baja California",venomous:!1,length:"2–3 ft",lifespan:"20–30 yrs",conservation:"LC",diet:"Pocket mice and other small desert rodents",short:"A small, unhurried desert boa prized for an unshakeable calm and famously low feeding needs.",long:"Rosy boas move slowly and deliberately, rarely bothering to flee or bite even when handled — a temperament that has made them a favorite among first-time snake keepers. In the wild they shelter under rocks through the heat of the day and emerge to hunt at dusk in the rocky deserts of the Southwest.",fact:"A healthy adult rosy boa can go a month or more between meals without any issue, one of the lowest feeding needs of any pet snake.",isPet:!0,isEndangered:!1,homeFeatured:!1,palette:{primary:"#b08a5a",secondary:"#7a4a2c",belly:"#e8d6ae"},pattern:"stripe",petDiet:{staple:"Frozen-thawed pinky or fuzzy mice",freq:"Every 10–14 days for adults",size:"One small mouse per feeding — they have modest appetites",tip:"Overfeeding is the main health risk for this species; resist the urge to feed more often than needed."}},{id:"rainbow-boa",name:"Rainbow Boa",latin:"Epicrates cenchria",family:"Boas",familyLatin:"Boidae",region:"South America east of the Andes",venomous:!1,length:"4–6 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Small mammals and birds",short:"Named for an iridescent sheen that scatters light into rainbow colors across its dark scales.",long:"Like the reticulated python, the rainbow boa's namesake shimmer comes from microscopic ridges on each scale that diffract light rather than from pigment — a phenomenon called structural iridescence. It's most vivid in bright direct light, flashing blues and purples across an otherwise reddish-brown body.",fact:"The iridescent effect is strongest on freshly-shed skin, fading slightly as the scales pick up wear between sheds.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#7a3a2c",secondary:"#3a1810",belly:"#d8b088"},pattern:"blotch"},{id:"emerald-tree-boa",name:"Emerald Tree Boa",latin:"Corallus caninus",family:"Boas",familyLatin:"Boidae",region:"Amazon Basin canopy",venomous:!1,length:"5–7 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Birds and small mammals, snatched mid-air or from branches",short:"The New World twin of the green tree python, with the same saddle perch and heat-sensing pits along its lips.",long:"This boa hunts almost entirely from an elevated coiled position, using heat-sensing labial pits to detect warm-blooded prey in total darkness. Its unusually long front teeth — the longest relative to head size of any non-venomous snake — let it snag birds out of the air before they can fully react.",fact:"Juveniles are born orange, yellow, or red and only develop their adult emerald green over the first year of life.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#2e7a4a",secondary:"#123a24",belly:"#dff0c8"},pattern:"diamond"},{id:"kenyan-sand-boa",name:"Kenyan Sand Boa",latin:"Gongylophis colubrinus",family:"Boas",familyLatin:"Boidae",region:"East Africa",venomous:!1,length:"1.5–2.5 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Small rodents, ambushed from beneath the sand",short:"A stout burrowing boa that spends nearly its entire life just beneath the surface of the sand.",long:"Sand boas have small eyes set high on a wedge-shaped head, ideal for lying buried with just the eyes and nostrils exposed. When a rodent passes within range it strikes upward and drags prey below the surface. Their small size and burrowing habits make them one of the lowest-maintenance boas in captivity.",fact:"Males and females look strikingly different — females can be nearly twice the length and much heavier-bodied than males.",isPet:!0,isEndangered:!1,homeFeatured:!1,palette:{primary:"#c9a25a",secondary:"#6b4a1e",belly:"#f0e0b0"},pattern:"blotch",petDiet:{staple:"Frozen-thawed hopper or fuzzy mice",freq:"Every 7–10 days for adults",size:"One appropriately-sized rodent, dropped near the sand surface",tip:"Feed on a shallow dish or tongs at the sand surface — burying live prey directly risks impaction from ingested substrate."}},{id:"madagascar-ground-boa",name:"Madagascar Ground Boa",latin:"Acrantophis madagascariensis",family:"Boas",familyLatin:"Boidae",region:"Madagascar",venomous:!1,length:"6–10 ft",lifespan:"20 yrs",conservation:"CR",diet:"Mammals and birds in dry forest and scrub",short:"Madagascar's largest snake and part of a boa lineage isolated on the island for tens of millions of years.",long:"Boas are otherwise absent from Africa, making Madagascar's ground and tree boas a biogeographic puzzle — their closest relatives live across the Pacific in the Americas and the Pacific islands. Habitat clearance for agriculture has fragmented its dry-forest range severely, and it is now classed as Critically Endangered.",fact:"Genetic studies suggest Madagascar's boas may descend from ancestors that rafted across the Indian Ocean on floating vegetation tens of millions of years ago.",isPet:!1,isEndangered:!0,homeFeatured:!1,palette:{primary:"#8a6b4a",secondary:"#4a3620",belly:"#e0d0a0"},pattern:"blotch"},{id:"gaboon-viper",name:"Gaboon Viper",latin:"Bitis gabonica",family:"Vipers",familyLatin:"Viperidae",region:"Sub-Saharan rainforest",venomous:!0,length:"4–6 ft",lifespan:"18–20 yrs",conservation:"LC",diet:"Rodents, birds, and small antelope",short:"The heaviest true viper alive, with the longest fangs of any venomous snake and camouflage to match a leaf pile.",long:"Gaboon vipers rely almost entirely on camouflage, remaining motionless on the forest floor where their intricate geometric pattern makes them nearly invisible among dead leaves. Their fangs can reach two inches long, and a single bite can deliver an enormous venom yield — but they are famously reluctant to bite, often tolerating being stepped near before ever striking.",fact:"Despite carrying enough venom to kill several adult humans, Gaboon vipers are responsible for very few bites, largely due to their calm, non-aggressive temperament.",isPet:!1,isEndangered:!1,homeFeatured:!0,palette:{primary:"#8a7a5a",secondary:"#3a3020",belly:"#e6ddc0"},pattern:"diamond"},{id:"eyelash-viper",name:"Eyelash Viper",latin:"Bothriechis schlegelii",family:"Vipers",familyLatin:"Viperidae",region:"Central America & northern South America",venomous:!0,length:"1.5–2.5 ft",lifespan:"10–15 yrs",conservation:"LC",diet:"Small mammals, frogs, and hummingbirds",short:"A small arboreal pit viper with modified scales above each eye that resemble spiky eyelashes.",long:"The raised scales that give this species its name are thought to help shield the eyes from twigs and rain while the snake perches motionless in dense vegetation, often near flowers where hummingbirds and other small prey visit. It shows dramatic color variation — populations range from mossy green to bright lemon yellow, sometimes even within the same clutch of eggs.",fact:"A lemon-yellow color morph found near Costa Rican waterfalls is nicknamed the 'oropel' and is prized by wildlife photographers.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#c9b23a",secondary:"#6b5a12",belly:"#f0e6a0"},pattern:"speckle"},{id:"western-diamondback",name:"Western Diamondback Rattlesnake",latin:"Crotalus atrox",family:"Vipers",familyLatin:"Viperidae",region:"Southwestern USA & Mexico",venomous:!0,length:"3–5 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Rodents, rabbits, and ground-nesting birds",short:"The rattlesnake responsible for more venomous snakebites in the US than any other species.",long:"The diamondback's rattle is made of loosely interlocking keratin segments, one added each time the snake sheds, that vibrate against each other to produce its warning buzz. Rather than an aggressive animal, it's a highly effective early-warning system — most bites happen when a snake is stepped on or handled rather than through unprovoked attack.",fact:"A rattlesnake's rattle segment count does not reliably indicate age, since segments regularly break off in the wild.",isPet:!1,isEndangered:!1,homeFeatured:!0,palette:{primary:"#a08a5a",secondary:"#4a3c1e",belly:"#e6dcae"},pattern:"diamond"},{id:"saw-scaled-viper",name:"Saw-scaled Viper",latin:"Echis carinatus",family:"Vipers",familyLatin:"Viperidae",region:"Middle East & South Asia",venomous:!0,length:"1–2.5 ft",lifespan:"10 yrs",conservation:"LC",diet:"Rodents, lizards, and scorpions",short:"A small but medically significant viper responsible for more human deaths than any other snake species worldwide.",long:"Despite its modest size, the saw-scaled viper's combination of dense population, proximity to farmland, and potent venom makes it one of the 'Big Four' snakes responsible for the majority of snakebite deaths in South Asia. Its name comes from a distinctive threat display — rubbing its rough, serrated side scales together to produce a rasping hiss.",fact:"Its warning hiss is made entirely with its scales, not its throat — the sound comes from friction between rows of saw-edged scales along its sides.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#b09a6a",secondary:"#5c4a26",belly:"#e8dcb0"},pattern:"speckle"},{id:"puff-adder",name:"Puff Adder",latin:"Bitis arietans",family:"Vipers",familyLatin:"Viperidae",region:"Sub-Saharan Africa & Arabia",venomous:!0,length:"3–4 ft",lifespan:"10–15 yrs",conservation:"LC",diet:"Rodents, birds, and small mammals",short:"Widespread and slow-moving, this species is blamed for more snakebite fatalities in Africa than any other.",long:"Puff adders rely on stillness, often lying across paths where people are likely to step on them rather than moving away. When threatened, they inflate the body and hiss loudly — the 'puff' that gives the species its name — as a warning before striking. Their strike is among the fastest of any snake, closing the gap in a fraction of a second.",fact:"High-speed camera studies have clocked puff adder strikes at under 70 milliseconds from start to finish.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#8a7a4a",secondary:"#3a3018",belly:"#e0d6a8"},pattern:"diamond"},{id:"horned-desert-viper",name:"Horned Desert Viper",latin:"Cerastes cerastes",family:"Vipers",familyLatin:"Viperidae",region:"North African & Arabian deserts",venomous:!0,length:"1–2 ft",lifespan:"10–15 yrs",conservation:"LC",diet:"Lizards, small mammals, and birds",short:"A sand-dwelling viper that moves sideways across loose dunes and sports a distinctive horn over each eye.",long:"Like other extreme desert specialists, the horned viper uses sidewinding locomotion — throwing loops of its body sideways across the sand — to minimize contact with hot ground and gain traction on loose dunes. It buries itself just beneath the surface by shuffling its body, leaving only its eyes and namesake horns exposed.",fact:"The horn-like scales above each eye may help shield the eyes from wind-blown sand, though their exact function is still debated.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#d9c48a",secondary:"#8a6b3a",belly:"#f0e6c0"},pattern:"band"},{id:"bushmaster",name:"Bushmaster",latin:"Lachesis muta",family:"Vipers",familyLatin:"Viperidae",region:"Central & South American rainforest",venomous:!0,length:"6–10 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Rodents, taken by ambush along forest trails",short:"The longest venomous snake in the Americas, and one of the only vipers in the world that lays eggs.",long:"Nearly all vipers give birth to live young, but the bushmaster is a rare exception, laying eggs which the female then coils around and guards until they hatch. It's an ambush specialist of deep, undisturbed rainforest, and its rarity combined with reclusive habits means it's very seldom encountered even by researchers.",fact:"Its scientific name muta ('mute') is a historical misnomer — bushmasters can vibrate their tail against leaf litter to produce a warning rattle-like sound.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#9a8452",secondary:"#453a1e",belly:"#e6dcb0"},pattern:"diamond"},{id:"copperhead",name:"Copperhead",latin:"Agkistrodon contortrix",family:"Vipers",familyLatin:"Viperidae",region:"Eastern & central USA",venomous:!0,length:"2–3 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Rodents, insects, frogs, and other snakes",short:"A common woodland pit viper whose bites, while painful, are rarely life-threatening to healthy adults.",long:"The copperhead's hourglass-shaped crossbands provide excellent camouflage against leaf litter, and it relies on this near-invisibility rather than fleeing when approached — a habit that leads to more bites than its mild venom potency alone would suggest. Juveniles have a bright yellow-green tail tip they wiggle to lure in frogs and lizards.",fact:"Copperheads are responsible for more venomous snakebites in the US each year than any other species, though fatalities are extremely rare with treatment.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#a8683a",secondary:"#5c341a",belly:"#e6c8a0"},pattern:"band"},{id:"king-cobra",name:"King Cobra",latin:"Ophiophagus hannah",family:"Elapids",familyLatin:"Elapidae",region:"South & Southeast Asia",venomous:!0,length:"10–18 ft",lifespan:"20 yrs",conservation:"VU",diet:"Almost exclusively other snakes, including venomous species",short:"The longest venomous snake in the world, and the only snake known to build a nest for its eggs.",long:"Unlike true cobras, the king cobra belongs to its own genus and specializes in eating other snakes, including highly venomous ones — its scientific name Ophiophagus literally means 'snake-eater'. Females build a nest of gathered leaf litter and vegetation, coiling nearby to guard it, one of the only nest-building behaviors known in any snake.",fact:"A single king cobra bite can deliver enough neurotoxic venom to kill an adult elephant.",isPet:!1,isEndangered:!0,homeFeatured:!0,palette:{primary:"#3a4a2c",secondary:"#161c10",belly:"#d0d0b0"},pattern:"band"},{id:"indian-cobra",name:"Indian Cobra",latin:"Naja naja",family:"Elapids",familyLatin:"Elapidae",region:"Indian subcontinent",venomous:!0,length:"4–6 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Rodents, frogs, and other snakes",short:"One of the 'Big Four' snakes of South Asia, famous for the spectacle-shaped marking on its raised hood.",long:"When threatened, the Indian cobra raises the front third of its body and spreads its neck ribs to form a flattened hood, often marked with a pair of dark 'spectacle' rings that make it look larger and more intimidating to predators. It is deeply woven into South Asian culture and religion, and figures prominently in traditional snake-charming, now widely restricted for conservation reasons.",fact:"The hood is formed by extending elongated ribs sideways under loose folded skin — there's no separate bony structure, just skin stretched over rib bones.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#3a3a2c",secondary:"#14140c",belly:"#c8c4a0"},pattern:"plain"},{id:"black-mamba",name:"Black Mamba",latin:"Dendroaspis polylepis",family:"Elapids",familyLatin:"Elapidae",region:"Sub-Saharan Africa",venomous:!0,length:"8–14 ft",lifespan:"11 yrs",conservation:"LC",diet:"Small mammals and birds",short:"Africa's longest venomous snake and, by reputation, its fastest — capable of short bursts near 12 mph.",long:"The black mamba is named not for its skin, which is olive to grey, but for the ink-black interior of its mouth, displayed in a gaping threat gesture before it strikes. It's a shy, alert animal that avoids confrontation whenever possible, but its speed, potent neurotoxic venom, and tendency to bite multiple times in defense made it historically one of the most feared snakes in Africa.",fact:"Before effective antivenom existed, an untreated black mamba bite was close to universally fatal, giving rise to its grim nickname 'the kiss of death'.",isPet:!1,isEndangered:!1,homeFeatured:!0,palette:{primary:"#5a5a48",secondary:"#26261c",belly:"#c8c4a8"},pattern:"plain"},{id:"inland-taipan",name:"Inland Taipan",latin:"Oxyuranus microlepidotus",family:"Elapids",familyLatin:"Elapidae",region:"Australian outback",venomous:!0,length:"6–8 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Native rodents, hunted in and around burrow systems",short:"The most venomous land snake in the world by toxicity, yet one of the least likely to ever bite a person.",long:"Drop for drop, the inland taipan's venom is the most potent of any land snake tested, evolved to kill fast-reacting native rats before they can bite back or flee into their burrow. Despite this fearsome chemistry, it lives in remote, sparsely populated arid Australia and is naturally shy, with no recorded human fatalities in modern times.",fact:"A single inland taipan bite carries enough venom, in theory, to kill well over a hundred adult humans.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#8a7248",secondary:"#3a3018",belly:"#dcd0a0"},pattern:"band"},{id:"coral-snake",name:"Eastern Coral Snake",latin:"Micrurus fulvius",family:"Elapids",familyLatin:"Elapidae",region:"Southeastern USA",venomous:!0,length:"2–3 ft",lifespan:"7 yrs",conservation:"LC",diet:"Other small snakes and lizards",short:"A brilliantly banded, reclusive burrower whose red-yellow-black pattern is mimicked by several harmless species.",long:"The coral snake's bold banding is a genuine warning signal, but several harmless species — most famously the scarlet kingsnake — have evolved nearly identical patterns to borrow that protection, a phenomenon called Batesian mimicry. Unlike pit vipers, coral snakes have small fixed fangs and must chew rather than strike-and-release, making bites rare despite potent neurotoxic venom.",fact:"The rhyme 'red touches yellow, kill a fellow; red touches black, friend of Jack' is a rough US field guide for telling coral snakes from their mimics — though it doesn't hold everywhere in their range.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#c93a3a",secondary:"#1a1a1a",belly:"#e0c840"},pattern:"band"},{id:"eastern-brown-snake",name:"Eastern Brown Snake",latin:"Pseudonaja textilis",family:"Elapids",familyLatin:"Elapidae",region:"Eastern & central Australia",venomous:!0,length:"5–7 ft",lifespan:"15 yrs",conservation:"LC",diet:"Rodents, especially around farmland",short:"Thin, fast, and alert, this species causes more snakebite deaths in Australia than any other.",long:"Eastern brown snakes are unusually nervous and quick to flee, but when cornered they can strike repeatedly with speed that makes them difficult to avoid safely. Their comfort around agricultural land, drawn in by abundant rodents feeding on stored grain, brings them into frequent contact with people, which combined with fast-acting venom explains their outsized role in Australian snakebite statistics.",fact:"Juvenile eastern brown snakes can be strikingly banded, and often look nothing like the plain-brown adults they'll grow into.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#8a6b42",secondary:"#3a2c18",belly:"#dccca0"},pattern:"plain"},{id:"death-adder",name:"Death Adder",latin:"Acanthophis antarcticus",family:"Elapids",familyLatin:"Elapidae",region:"Australia & New Guinea",venomous:!0,length:"2–3 ft",lifespan:"10–15 yrs",conservation:"LC",diet:"Lizards, birds, and small mammals",short:"An elapid that looks and hunts like a viper — a squat ambush predator that lures prey with its tail.",long:"Despite belonging to the elapid family alongside cobras and mambas, death adders have converged on a completely different hunting style: lying half-buried and motionless, then flicking a thin worm-like tail tip to lure curious prey within striking range. This ambush strategy, combined with camouflage, gives it one of the fastest strikes of any Australian snake.",fact:"The 'caudal luring' technique — wiggling the tail like a worm — has evolved independently in several unrelated snake families around the world.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#a08558",secondary:"#4a3a1e",belly:"#e0d4a8"},pattern:"band"},{id:"corn-snake",name:"Corn Snake",latin:"Pantherophis guttatus",family:"Colubrids",familyLatin:"Colubridae",region:"Southeastern USA",venomous:!1,length:"3–5 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Mice and small rats",short:"Active, food-motivated, and endlessly color-bred — often the single most recommended first pet snake.",long:"Corn snakes get their name either from the corn-like pattern on their belly scales or from a habit of hunting rodents in stored grain corn cribs — accounts differ. They're excellent climbers and escape artists in captivity, but their easy handling, modest size, and huge range of selectively bred colors have made them a staple of the reptile hobby for decades.",fact:"Wild-type corn snakes are already strikingly orange and red, which is likely why early European settlers confused them with venomous copperheads and often killed them on sight.",isPet:!0,isEndangered:!1,homeFeatured:!0,palette:{primary:"#c9612c",secondary:"#7a2e10",belly:"#f0c888"},pattern:"blotch",petDiet:{staple:"Frozen-thawed mice, scaled up in size as the snake grows",freq:"Every 5–7 days for adults, more often for hatchlings",size:"One mouse roughly as wide as the snake's midsection",tip:"Warm frozen-thawed prey to near body temperature before offering — cold food is a common reason for refused meals."}},{id:"california-kingsnake",name:"California Kingsnake",latin:"Lampropeltis californiae",family:"Colubrids",familyLatin:"Colubridae",region:"Western USA & northern Mexico",venomous:!1,length:"3–4 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Rodents, lizards, and other snakes — including rattlesnakes",short:"A hardy, food-driven constrictor that is naturally resistant to the venom of many pit vipers it preys on.",long:"Kingsnakes earn their name by eating other snakes, including venomous rattlesnakes, thanks to a natural resistance that limits the effect of pit viper venom in their bloodstream. This same instinct makes them dangerous to their own kind — kingsnakes must always be housed alone, since two together will often result in one eating the other.",fact:"Farmers historically welcomed kingsnakes onto their land specifically because they help control local rattlesnake populations.",isPet:!0,isEndangered:!1,homeFeatured:!1,palette:{primary:"#1c1c1c",secondary:"#000000",belly:"#e8e4d0"},pattern:"band",petDiet:{staple:"Frozen-thawed mice",freq:"Every 5–7 days for adults",size:"One mouse per feeding, sized to the snake's girth",tip:"Never house with another snake, even briefly — kingsnakes will attempt to eat cage-mates, including their own species."}},{id:"garter-snake",name:"Garter Snake",latin:"Thamnophis sirtalis",family:"Colubrids",familyLatin:"Colubridae",region:"Across most of North America",venomous:!1,length:"1.5–3 ft",lifespan:"6–10 yrs",conservation:"LC",diet:"Earthworms, fish, amphibians, and slugs",short:"North America's most widespread snake, and one of the only pet snakes that thrives on a fish-and-worm diet.",long:"Garter snakes are diurnal, meaning they're active by day rather than at night like most popular pet species, so owners actually get to watch them hunt, bask, and explore. Unusually for a colubrid, many populations eat mostly fish, amphibians, and earthworms rather than rodents, and some individuals produce a mild toxin in their saliva that helps subdue slippery prey like toads.",fact:"Garter snakes in some regions den together by the thousands in communal winter hibernation sites called hibernacula.",isPet:!0,isEndangered:!1,homeFeatured:!1,palette:{primary:"#2c5a3a",secondary:"#14301c",belly:"#c8d8a0"},pattern:"stripe",petDiet:{staple:"Whole thawed fish (e.g. silversides), nightcrawlers, and appropriately sized rodents",freq:"Every 3–5 days — garters have faster metabolisms than most pet snakes",size:"Small enough to swallow easily; use a fish-based diet with a reptile multivitamin dusted on",tip:"A fish-only diet can cause a thiamine deficiency over time — rotate in earthworms or vitamin-dusted prey."}},{id:"milk-snake",name:"Milk Snake",latin:"Lampropeltis triangulum",family:"Colubrids",familyLatin:"Colubridae",region:"Canada to South America",venomous:!1,length:"2–4 ft",lifespan:"12–20 yrs",conservation:"LC",diet:"Rodents, lizards, and other snakes",short:"A coral snake mimic with one of the largest north-to-south ranges of any snake in the Americas.",long:"Milk snakes get their misleading name from an old, false belief that they milked cows in barns — in reality they were likely just hunting the rodents barns attract. Many populations show bold red-black-yellow banding that closely mimics venomous coral snakes sharing their range, offering protection from predators without any of the actual risk.",fact:"The milk snake's range stretches from southeastern Canada all the way to Ecuador, one of the broadest north-south ranges of any terrestrial snake species.",isPet:!0,isEndangered:!1,homeFeatured:!1,palette:{primary:"#c93a3a",secondary:"#1a1a1a",belly:"#e0c840"},pattern:"band",petDiet:{staple:"Frozen-thawed mice",freq:"Every 6–8 days for adults",size:"One mouse sized to the snake's girth",tip:"Like kingsnakes, milk snakes are opportunistic snake-eaters — house separately and never together."}},{id:"boomslang",name:"Boomslang",latin:"Dispholidus typus",family:"Colubrids",familyLatin:"Colubridae",region:"Sub-Saharan Africa",venomous:!0,length:"4–6 ft",lifespan:"8–10 yrs",conservation:"LC",diet:"Chameleons, birds, and eggs",short:"A rear-fanged tree snake whose slow-acting hemotoxic venom is unusually dangerous for a colubrid.",long:"Most colubrids are harmless or only mildly venomous, but the boomslang is a striking exception — its venom causes uncontrolled internal and external bleeding, and its rear-positioned fangs mean it must open its jaw unusually wide to deliver an effective bite. Because symptoms can take hours to appear, bites have historically been mistaken for minor.",fact:"Herpetologist Karl Schmidt died from a boomslang bite in 1957 after documenting his own symptoms in a detailed diary right up until the end, a chilling scientific record that helped later doctors understand its venom's delayed onset.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#2e6b3a",secondary:"#123018",belly:"#c8dca0"},pattern:"plain"},{id:"rat-snake",name:"Black Rat Snake",latin:"Pantherophis obsoletus",family:"Colubrids",familyLatin:"Colubridae",region:"Eastern & central USA",venomous:!1,length:"4–6 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Rodents, birds, and eggs",short:"A superb climber often found high in barns and trees, and one of the best natural rodent controllers around.",long:"Rat snakes are excellent climbers, using specially keeled belly scales to grip vertical bark and even brick. Farmers have long tolerated — and often welcomed — them for their appetite for barn rodents. When threatened, they vibrate their tail rapidly against dry leaves, producing a rattling sound that can startle people into mistaking them for a venomous species.",fact:"Rat snakes are constrictors but use a distinctive slow squeeze that gradually tightens with each exhale of the prey, rather than a single sudden clamp.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#1e1e1e",secondary:"#000000",belly:"#c8c8c0"},pattern:"plain"},{id:"hognose-snake",name:"Eastern Hognose Snake",latin:"Heterodon platirhinos",family:"Colubrids",familyLatin:"Colubridae",region:"Eastern USA",venomous:!1,length:"1.5–3 ft",lifespan:"12–18 yrs",conservation:"LC",diet:"Almost exclusively toads",short:"Famous for a dramatic death-feigning act — flipping belly-up, tongue out, and playing convincingly dead.",long:"When a hognose snake's initial bluff — hissing, flattening its neck like a mini-cobra — fails to deter a predator, it commits fully to a second act: writhing violently, opening its mouth, and flopping onto its back to play dead. If flipped right-side up, it will often flip itself belly-up again, seemingly convinced that the 'correct' dead posture is upside down.",fact:"Hognose snakes have enlarged rear teeth specialized for popping inflated toads, one of their main prey items, which puff up as a defense against most other predators.",isPet:!0,isEndangered:!1,homeFeatured:!1,palette:{primary:"#8a7248",secondary:"#3a3018",belly:"#dcd0a0"},pattern:"blotch",petDiet:{staple:"Frozen-thawed mice scented with toad or lightly scented feeder to encourage feeding response",freq:"Every 7–10 days for adults",size:"One mouse per feeding",tip:"Wild hognose snakes eat mostly toads, so captive-bred, established feeders on rodents are strongly preferred over wild-caught individuals."}},{id:"vine-snake",name:"Brown Vine Snake",latin:"Oxybelis aeneus",family:"Colubrids",familyLatin:"Colubridae",region:"Central & South America",venomous:!0,length:"3–5 ft",lifespan:"10 yrs",conservation:"LC",diet:"Lizards, tree frogs, and small birds",short:"An impossibly thin, twig-like ambush hunter that relies on stillness rather than speed to catch prey.",long:"The vine snake's pencil-thin body is such effective camouflage among branches that it can hold a striking pose for long stretches, waiting for a lizard to wander within reach before lunging with surprising speed. It is mildly venomous, with rear fangs suited to small lizard prey rather than defense against larger animals.",fact:"Its extreme slenderness means a vine snake several feet long can weigh less than a tablespoon of water.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#8a6b42",secondary:"#4a3a1e",belly:"#d8cc9a"},pattern:"plain"},{id:"gopher-snake",name:"Gopher Snake",latin:"Pituophis catenifer",family:"Colubrids",familyLatin:"Colubridae",region:"Western North America",venomous:!1,length:"4–7 ft",lifespan:"12–15 yrs",conservation:"LC",diet:"Ground squirrels, gophers, and other burrowing rodents",short:"A rattlesnake mimic that hisses, flattens its head, and vibrates its tail to bluff its way past predators.",long:"Gopher snakes have a specialized flap of tissue near the windpipe that vibrates loudly as they exhale, producing a hiss deeper and louder than most other colubrids can manage. Combined with a flattened, triangular-looking head and a vibrating tail, this bluff is often convincing enough to make people — and predators — mistake it for a rattlesnake.",fact:"Their powerful hiss comes from a unique tracheal structure called an epiglottal keel, essentially a built-in vocal cord for making noise, not venom.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#c9b26a",secondary:"#6b5a2e",belly:"#f0e6c0"},pattern:"blotch"},{id:"grass-snake",name:"Grass Snake",latin:"Natrix helvetica",family:"Colubrids",familyLatin:"Colubridae",region:"Western Europe",venomous:!1,length:"2–4 ft",lifespan:"15–25 yrs",conservation:"LC",diet:"Frogs, toads, fish, and newts",short:"A common European wetland snake that plays dead with a theatrical flourish, releasing a foul musk as it does.",long:"Grass snakes are strong swimmers frequently found near ponds, hunting amphibians both in and out of the water. Their defensive repertoire rivals the hognose snake's — when cornered they may hiss, strike with a closed mouth, release a pungent musk from glands near the tail, and finally go limp, mouth agape, in a convincing death display.",fact:"Grass snakes have been recorded 'resurrecting' from their death-feigning act within seconds once a perceived threat has moved away.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#4a6b3a",secondary:"#1e301c",belly:"#d0d8a8"},pattern:"band"},{id:"yellow-bellied-sea-snake",name:"Yellow-bellied Sea Snake",latin:"Hydrophis platurus",family:"Sea Snakes",familyLatin:"Elapidae (Hydrophiinae)",region:"Pacific & Indian Ocean, open water",venomous:!0,length:"2–3 ft",lifespan:"10 yrs",conservation:"LC",diet:"Small fish, caught at the ocean surface",short:"The most widely distributed snake species on Earth, spending its entire life adrift on the open ocean.",long:"Unlike sea kraits, this species never comes ashore at all — it mates, gives birth, and hunts entirely at sea, drifting with ocean currents across a range spanning the Indian and Pacific Oceans. Its paddle-shaped tail and side-flattened body make it a strong swimmer, and it can absorb some oxygen directly through its skin to extend dives.",fact:"Individuals have been found stranded thousands of miles from the nearest population, carried by ocean currents alone.",isPet:!1,isEndangered:!1,homeFeatured:!0,palette:{primary:"#2c2c1e",secondary:"#0c0c08",belly:"#e0c840"},pattern:"plain"},{id:"banded-sea-krait",name:"Banded Sea Krait",latin:"Laticauda colubrina",family:"Sea Snakes",familyLatin:"Elapidae (Laticaudinae)",region:"Indo-Pacific coral reefs",venomous:!0,length:"3–4 ft",lifespan:"15 yrs",conservation:"LC",diet:"Eels, hunted inside reef crevices",short:"A striking black-and-blue-banded hunter that, unlike true sea snakes, still comes ashore to rest and lay eggs.",long:"Sea kraits are amphibious specialists that split their lives between reef water and land, digesting meals, mating, and laying eggs on rocky shorelines. Their flattened paddle tail helps them chase eels deep into narrow reef crevices, a hunting style few other predators can match.",fact:"Sea kraits must return to fresh water periodically to rehydrate, since — unlike fully marine sea snakes — they cannot fully process seawater.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#1c2c4a",secondary:"#0a1220",belly:"#e0dcc0"},pattern:"band"},{id:"beaked-sea-snake",name:"Beaked Sea Snake",latin:"Hydrophis schistosus",family:"Sea Snakes",familyLatin:"Elapidae (Hydrophiinae)",region:"Indo-Pacific coastal waters",venomous:!0,length:"3–4.5 ft",lifespan:"10 yrs",conservation:"LC",diet:"Catfish and other bottom-dwelling fish",short:"One of the most medically significant sea snakes, frequently caught accidentally in coastal fishing nets.",long:"Most sea snake bites on humans occur when fishers handle nets or catch containing this species by accident, making it responsible for a disproportionate share of sea snake envenomations worldwide. It hunts along muddy coastal seafloors for catfish, using a distinctively upturned snout to help probe the substrate.",fact:"Fishing communities across South and Southeast Asia have developed specific handling protocols specifically because of how often this species turns up in nets.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#8a8a6a",secondary:"#3a3a26",belly:"#e6e0c0"},pattern:"band"},{id:"olive-sea-snake",name:"Olive Sea Snake",latin:"Aipysurus laevis",family:"Sea Snakes",familyLatin:"Elapidae (Hydrophiinae)",region:"Coral Sea & northern Australian coast",venomous:!0,length:"3–5 ft",lifespan:"15 yrs",conservation:"LC",diet:"Reef fish and fish eggs",short:"A curious, robust reef-dweller known to approach and investigate divers rather than flee.",long:"Olive sea snakes are unusually bold around divers compared with most sea snakes, sometimes swimming right up to investigate — behavior researchers believe may be linked to mistaking divers for potential mates during breeding season. They have light-sensing cells in their tail skin, letting them detect whether their tail is still hidden in a crevice while their head is elsewhere.",fact:"Photoreceptors in the tail skin appear to help the snake know when its rear half is fully concealed in a den, even without being able to see it.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#6b7a4a",secondary:"#2c3a1c",belly:"#d8dcae"},pattern:"plain"},{id:"brown-house-snake",name:"Brown House Snake",latin:"Boaedon fuliginosus",family:"House & Mole Snakes",familyLatin:"Lamprophiidae",region:"Sub-Saharan Africa",venomous:!1,length:"2–4 ft",lifespan:"12–15 yrs",conservation:"LC",diet:"Rodents, especially around human dwellings",short:"A docile, unfussy rodent-hunter that thrives around farms and homes, and adapts easily to captivity.",long:"As its name suggests, the brown house snake readily moves into buildings and outbuildings, drawn by the rodents that gather around stored food. It's an easy keeper in the pet trade thanks to a reliable feeding response and tolerance for a wide range of enclosure setups, making it a popular, low-cost beginner species outside the US and Europe.",fact:"Because it's such a reliable, food-driven eater, breeders sometimes use brown house snakes to 'jump-start' the feeding response of a reluctant snake of another species by scenting prey with house-snake musk.",isPet:!0,isEndangered:!1,homeFeatured:!1,palette:{primary:"#6b4a2c",secondary:"#2c1c10",belly:"#d8c49a"},pattern:"stripe",petDiet:{staple:"Frozen-thawed mice",freq:"Every 5–7 days for adults",size:"One mouse per feeding, sized to the snake's girth",tip:"One of the most reliable feeders in the hobby — refusals are uncommon and usually tied to temperature or shedding."}},{id:"mole-snake",name:"Mole Snake",latin:"Pseudaspis cana",family:"House & Mole Snakes",familyLatin:"Lamprophiidae",region:"Southern Africa",venomous:!1,length:"4–6 ft",lifespan:"15–20 yrs",conservation:"LC",diet:"Moles, mole rats, and other burrowing mammals",short:"A powerful burrowing constrictor built almost entirely around a diet of underground rodents.",long:"Mole snakes spend much of their lives underground, following the tunnel systems of mole rats and other burrowing rodents they specialize in hunting. They're proportionally very muscular, an adaptation for pushing through soil and overpowering prey in the confines of a tunnel where there's little room to maneuver.",fact:"Mole snakes give birth to some of the largest litters of any live-bearing snake, with records of over 90 young from a single female.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#5c4a32",secondary:"#241c10",belly:"#c8b890"},pattern:"plain"},{id:"egg-eating-snake",name:"African Egg-eating Snake",latin:"Dasypeltis scabra",family:"House & Mole Snakes",familyLatin:"Lamprophiidae",region:"Sub-Saharan Africa",venomous:!1,length:"2–3 ft",lifespan:"10–15 yrs",conservation:"LC",diet:"Bird eggs — exclusively, at every life stage",short:"A snake with virtually no functional teeth, built entirely around swallowing eggs whole and crushing them internally.",long:"This species has evolved bony spurs projecting from its spine into the throat, which puncture and crack a swallowed egg once it reaches the esophagus. It then regurgitates the crushed shell as a neat, compact pellet and swallows only the contents — an extraordinarily specialized adaptation found in almost no other snake lineage.",fact:"An egg-eating snake's jaw can stretch to swallow an egg several times wider than its own head, then contract back down afterward as if nothing happened.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#8a7248",secondary:"#3a3018",belly:"#dcd0a0"},pattern:"blotch"},{id:"javan-file-snake",name:"Javan File Snake",latin:"Acrochordus javanicus",family:"Wart Snakes",familyLatin:"Acrochordidae",region:"Southeast Asian rivers & estuaries",venomous:!1,length:"5–8 ft",lifespan:"10–15 yrs",conservation:"LC",diet:"Fish, caught in murky water using touch rather than sight",short:"A baggy-skinned, fully aquatic snake so specialized for water that it's almost helpless on land.",long:"File snakes have loose, ill-fitting skin covered in small, rough, granular scales — an adaptation that grips slippery fish far better than smooth scales would, at the cost of streamlined movement. They hunt in murky, low-visibility water using sensitive skin receptors to detect fish moving nearby rather than relying on sight.",fact:"A file snake's skin is so loose it can rotate almost independently of the muscle and bone underneath, helping it keep hold of a thrashing fish.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#4a4a3a",secondary:"#1c1c14",belly:"#c0c0a8"},pattern:"speckle"},{id:"elephant-trunk-snake",name:"Elephant Trunk Snake",latin:"Acrochordus javanicus (trade name)",family:"Wart Snakes",familyLatin:"Acrochordidae",region:"Southeast Asian rivers",venomous:!1,length:"5–7 ft",lifespan:"10 yrs",conservation:"LC",diet:"Fish",short:"The common trade name for the file snake, describing its thick, wrinkled, grey hide.",long:"'Elephant trunk snake' is simply the aquarium and leather trade nickname for the Javan file snake, referencing its loose, deeply wrinkled grey skin that looks remarkably like the surface of an elephant's trunk. It's almost never seen out of water voluntarily, and its clumsy, awkward movements on land stand in sharp contrast to its efficient, sinuous swimming.",fact:"Its skin has historically been harvested for exotic leather goods, sold under names that intentionally obscure that the source is a snake rather than a mammal.",isPet:!1,isEndangered:!1,homeFeatured:!1,palette:{primary:"#5a5a4a",secondary:"#242418",belly:"#c8c4a8"},pattern:"speckle"},{id:"antiguan-racer",name:"Antiguan Racer",latin:"Alsophis antiguae",family:"Colubrids",familyLatin:"Colubridae",region:"Antigua, Caribbean",venomous:!1,length:"2–3 ft",lifespan:"10–15 yrs",conservation:"CR",diet:"Lizards, primarily Anolis skinks",short:"Once down to fewer than 50 snakes on a single rat-infested islet — now a flagship conservation recovery story.",long:"Invasive rats and mongooses introduced by European settlers wiped the Antiguan racer out from the mainland entirely, leaving a single tiny population on rat-free Great Bird Island. A long-running eradication and reintroduction program removed invasive predators from several nearby islets and reintroduced racers to them, growing the total population from under 50 to several hundred.",fact:"The Antiguan racer recovery program is widely cited in conservation biology as one of the clearest proofs that invasive-species removal alone can reverse a species' path toward extinction.",isPet:!1,isEndangered:!0,homeFeatured:!1,palette:{primary:"#6b5a3a",secondary:"#2c2418",belly:"#d8cc9a"},pattern:"speckle"},{id:"saint-lucia-racer",name:"Saint Lucia Racer",latin:"Erythrolamprus ornatus",family:"Colubrids",familyLatin:"Colubridae",region:"Saint Lucia, Caribbean",venomous:!1,length:"2 ft",lifespan:"10 yrs",conservation:"CR",diet:"Small lizards",short:"Possibly the rarest snake alive, surviving only on one small mongoose-free offshore islet.",long:"The Saint Lucia racer was thought extinct for decades after introduced mongooses eliminated it from the main island, until a small relict population was rediscovered on the 30-acre Maria Major islet in the 1970s. With fewer than a few hundred individuals thought to remain in a single location, it remains one of the most acute single-population extinction risks among reptiles worldwide.",fact:"Conservationists have begun a careful captive-breeding and second-island program specifically because having every last individual on one small islet is an existential risk from a single hurricane or fire.",isPet:!1,isEndangered:!0,homeFeatured:!1,palette:{primary:"#5c4a30",secondary:"#241c10",belly:"#c8b890"},pattern:"speckle"},{id:"louisiana-pine-snake",name:"Louisiana Pine Snake",latin:"Pituophis ruthveni",family:"Colubrids",familyLatin:"Colubridae",region:"Louisiana & Texas, USA",venomous:!1,length:"4–6 ft",lifespan:"15 yrs",conservation:"EN",diet:"Pocket gophers, almost exclusively",short:"One of North America's rarest snakes, tied almost entirely to a single burrowing rodent and vanishing pine forest.",long:"This species depends on the open, fire-managed longleaf pine forest of the historic South, and specifically on the burrow systems dug by Baird's pocket gopher, its near-exclusive prey. Decades of fire suppression and pine forest conversion to farmland have shrunk both habitat and prey base dramatically, making sightings genuinely rare even within its historic range.",fact:"Louisiana pine snakes lay some of the largest eggs relative to body size of any North American snake — a single clutch may contain only 3–5 eggs, but each is enormous.",isPet:!1,isEndangered:!0,homeFeatured:!1,palette:{primary:"#8a7a52",secondary:"#3a3420",belly:"#e0d6a8"},pattern:"blotch"},{id:"round-island-boa",name:"Round Island Boa",latin:"Casarea dussumieri",family:"Boas",familyLatin:"Boidae",region:"Round Island, Mauritius",venomous:!1,length:"3–5 ft",lifespan:"15 yrs",conservation:"EN",diet:"Lizards, especially skinks and geckos",short:"The last living member of a distinct boa sub-family, confined to a single small island off Mauritius.",long:"Introduced goats and rabbits stripped Round Island's native vegetation to bare rock through the 20th century, pushing this uniquely hinge-jawed boa to the edge of extinction. A sustained restoration effort — removing invasive grazers and replanting native flora — has allowed the population to slowly stabilize, though it remains found nowhere else on Earth.",fact:"Round Island boas have an unusual hinged upper jaw, flexible even by snake standards, that may help them better grip smooth-scaled skinks.",isPet:!1,isEndangered:!0,homeFeatured:!1,palette:{primary:"#a08a5a",secondary:"#4a3c1e",belly:"#e6dcae"},pattern:"blotch"},{id:"aruba-rattlesnake",name:"Aruba Rattlesnake",latin:"Crotalus durissus unicolor",family:"Vipers",familyLatin:"Viperidae",region:"Aruba",venomous:!0,length:"2.5–3.5 ft",lifespan:"15 yrs",conservation:"EN",diet:"Small mammals and lizards",short:"Confined entirely to the arid scrub of one small Caribbean island, with an estimated population in the low hundreds.",long:"The Aruba rattlesnake is a subspecies found nowhere else on the planet, restricted to the dry, cactus-studded interior of a single small island. Tourism-driven development and continued persecution by residents who fear its rattle remain its biggest ongoing threats, despite the species posing little practical danger given how rarely it's encountered.",fact:"Local conservation groups now run public education campaigns specifically to reduce killing of the species out of fear, since habitat loss alone already puts unsustainable pressure on such a small population.",isPet:!1,isEndangered:!0,homeFeatured:!1,palette:{primary:"#9a8458",secondary:"#4a3c1e",belly:"#e0d4a8"},pattern:"diamond"},{id:"eastern-indigo-snake",name:"Eastern Indigo Snake",latin:"Drymarchon couperi",family:"Colubrids",familyLatin:"Colubridae",region:"Southeastern USA",venomous:!1,length:"6–8 ft",lifespan:"20–25 yrs",conservation:"VU",diet:"Almost anything it can overpower, including venomous snakes",short:"North America's longest native snake, with an iridescent blue-black sheen and an appetite for rattlesnakes.",long:"Eastern indigo snakes rely heavily on gopher tortoise burrows for shelter, especially through cooler months, tying their fate closely to that of another declining species. Longleaf pine habitat loss across the Southeast has cut their range sharply, but captive breeding and reintroduction programs across Florida, Georgia, and Alabama are steadily rebuilding wild populations.",fact:"Indigo snakes are immune to pit viper venom and will actively hunt and eat rattlesnakes, helping keep local rattlesnake numbers in check.",isPet:!1,isEndangered:!0,homeFeatured:!0,palette:{primary:"#1a2436",secondary:"#0a0e18",belly:"#3a4a5c"},pattern:"plain"}],t=Object.fromEntries(a.map(e=>[e.id,e])),n={CR:"Critically Endangered",EN:"Endangered",VU:"Vulnerable",NT:"Near Threatened",LC:"Least Concern"};window.SNAKES=a;window.SNAKE_BY_ID=t;window.CONSERVATION_LABEL=n;
